import time

class SimpleCache:
    def __init__(self, ttl: int = 300):
        self._cache = {}
        self._ttl = ttl

    def get(self, key: str):
        if key in self._cache:
            return self._cache[key]
        return None

    def set(self, key: str, value):
        self._cache[key] = value
